/**
 * @param {number} n The number of nodes (0 to n-1).
 * @param {number[][]} edges An array of edges [u, v, w].
 * @return {number} The number of successfully added edges.
 */
function solve(n, edges) {
    // DSU structure initialization
    const parent = Array(n).fill(0).map((_, i) => i);
    // dist[i] stores the parity of the path weight from node i to its current parent.
    const dist = Array(n).fill(0); 
    // Size optimization for union by size
    const size = Array(n).fill(1);

    /**
     * Finds the root of node i and performs path compression, updating distances along the way.
     * @param {number} i 
     * @returns {number} The root of the set containing i.
     */
    function find(i) {
        if (parent[i] === i) {
            return i;
        }

        // Store original parent before recursion
        const old_parent = parent[i];

        // Recurse to find the ultimate root r
        const root = find(old_parent);

        // Update distance: dist[i] (i -> old_parent) XOR dist[old_parent] (old_parent -> root)
        dist[i] = dist[i] ^ dist[old_parent];

        // Path compression
        parent[i] = root;

        return root;
    }

    let acceptedEdgesCount = 0;

    for (const [u, v, w] of edges) {
        const rootU = find(u);
        const rootV = find(v);

        if (rootU === rootV) {
            // Case 1: u and v are already in the same component (Cycle formed)

            // Current path parity from u to v (via rootU) is dist[u] ^ dist[v].
            // The new cycle parity is (dist[u] ^ dist[v]) ^ w.
            // We require this sum to be 0 (even).
            const existingPathParity = dist[u] ^ dist[v];

            if (existingPathParity === w) {
                // Cycle parity is 0 (Even). Accept the edge.
                acceptedEdgesCount++;
            } else {
                // Cycle parity is 1 (Odd). Reject the edge.
            }
        } else {
            // Case 2: u and v are in different components (Merge)

            // Union by size: Attach smaller tree to the root of the larger tree.
            if (size[rootU] < size[rootV]) {
                // Swap roles so rootU is always the larger or equal tree
                [rootU, rootV] = [rootV, rootU];
                [u, v] = [v, u];
                // Note: We swap u and v indices to maintain consistent logic below
                // dist[u] and dist[v] still refer to the correct relative parities found earlier.
            }

            // Merge rootV into rootU
            parent[rootV] = rootU;
            size[rootU] += size[rootV];

            // Calculate the new distance for rootV relative to the new parent rootU.
            // We need dist[rootV] such that: 
            // Parity(rootV -> rootU) = dist[rootV]
            // Path: rootV -> v (dist[v]) -> u (w) -> rootU (dist[u])
            // Parity = dist[v] ^ w ^ dist[u]

            // Since we might have swapped u and v internally, we must use the original nodes 
            // corresponding to the components merged (the one whose root became rootV).
            // Let's stick to the original u and v for clarity, assuming we didn't swap them above.
            // If we stick to the initial u, v:
            // Path from rootV to rootU: rootV -> v (dist[v]) -> u (w) -> rootU (dist[u])
            const newDistRVtoRU = dist[v] ^ w ^ dist[u];

            // Since we might have swapped, we must be careful about which dist[i] refers to which node.
            // Let's revert to standard union without swapping (simpler for distance tracking):

            // Re-find roots if swap happened internally above (safer approach, although slightly redundant)
            // Since we are not using rank/size optimization for distance calculation, let's skip size optimization 
            // or implement it carefully. Given the constraints, simple union is fine.

            // --- Resetting logic to use simple union (V -> U) ---
            const final_rootU = find(u);
            const final_rootV = find(v);

            if (final_rootU !== final_rootV) {
                // Union V into U
                parent[final_rootV] = final_rootU;

                // Distance calculation:
                // Path: final_rootV -> v (dist[v]) -> u (w) -> final_rootU (dist[u])
                // Set dist[final_rootV] = parity(final_rootV -> final_rootU)
                const newDist = dist[v] ^ w ^ dist[u];
                dist[final_rootV] = newDist;

                acceptedEdgesCount++;
            }
        }
    }

    return acceptedEdgesCount;
